-- Enrichment marathon batch: Chegg, Chemtool, CherryTree, Chili Piper, Chime, Chisel, Chrome Remote Desktop, Churnkey

-- ── Chegg ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chegg is a publicly traded (NYSE: CHGG) education technology company founded in 2005 that sells textbook rentals, homework help, expert-answered questions, and study tools to college students. Once valued at over 14 billion dollars, Chegg has suffered one of the most severe, well-documented business collapses in edtech history since 2023, as ChatGPT and other generative AI tools eroded its subscriber base, driving a stock price crash of roughly 99 percent and workforce cuts of nearly half its staff.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Around $9.95/month (Chegg Study, billed annually)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Roughly 1,840 employees as of December 2025, down from about 3,270 in 2023 following two rounds of layoffs$q$, company_size),
  headquarters = COALESCE($q$Santa Clara, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chegg Review 2026: Pricing, Features, and the AI Disruption Story$q$, seo_title),
  seo_meta_description = COALESCE($q$Chegg offers textbook rentals, homework help, and study tools for students. See current pricing, features, and how ChatGPT and AI upended its business.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chegg is an American education technology company, publicly traded on the NYSE under the ticker CHGG, that has sold textbook rentals, step-by-step homework solutions, expert-answered questions, writing help, and online tutoring to college students for nearly two decades. Its roots trace to Cheggpost, a Craigslist-style board for Iowa State University students launched in October 2000 by Josh Carlson, Mike Seager, and Mark Fiddleke. Aayush Phumbhra and Osman Rashid incorporated the company in 2005, pivoted into textbook rentals modeled on Netflix, and relaunched the service as Chegg in December 2007. Chegg went public in November 2013, raising about 187.5 million dollars, and under longtime CEO Dan Rosensweig grew into a subscription business built around Chegg Study, Chegg Study Pack, Chegg Writing, Chegg Math Solver, and tutoring. This profile deliberately covers Chegg's current, widely reported business decline rather than glossing over it, because it materially defines the company today. ChatGPT's launch in November 2022 hit Chegg's core value proposition directly: free AI tools could answer many of the same homework questions Chegg charged a monthly subscription for. Chegg's own CEO acknowledged the impact in a May 2023 warning, and the company has since lost more than 500,000 subscribers. Chegg's stock has fallen roughly 99 percent from its 2021 peak, wiping out tens of billions in market value. The company has also sued Google, arguing that AI Overviews in search results have diverted traffic and revenue away from publishers like Chegg. Layoffs followed in two waves during 2025: about 22 percent of staff in May and a further 45 percent of the remaining workforce in October, cutting total headcount to roughly 1,840 by year-end, down from about 3,270 in 2023. Dan Rosensweig returned as President and CEO in October 2025 as part of the restructuring. Rather than sell the company, Chegg's board explored a sale through advisor Goldman Sachs in 2025 but ultimately decided in October 2025 to remain a standalone public company, betting instead on a strategic pivot toward business-to-business skilling: professional language learning, workplace-readiness training, and AI-skills courses aimed at enterprise learning and development budgets rather than individual students. That segment was expected to generate roughly 70 million dollars in 2025 revenue with targeted double-digit growth in 2026. In June 2026, Chegg regained compliance with the NYSE's minimum share price listing standard, leading its board to shelve a previously considered reverse stock split. For readers evaluating Chegg today, the product still functions largely as it always has, textbook rentals, homework help, and study tools, priced around 9.95 to 19.95 dollars per month depending on the plan, but the company's near-term financial trajectory, subscriber trends, and even its long-term independence remain genuinely uncertain given the depth of the AI-driven disruption to its core market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '81681037-3e0b-4157-82ac-707a4372e951';

