-- ── Chemtool ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chemtool is a free, open-source 2D chemical structure editor for Linux and other X11-based Unix-like systems, built with the GTK+ toolkit. Originally written by German chemistry student Thomas Volk and later maintained by other contributors, it lets chemists, educators, and students sketch organic molecules, bond diagrams, and reaction schemes, then export them to formats such as PNG, SVG, EPS, XFig, and MDL molfile. It is distributed under the GNU General Public License and remains available through most major Linux distribution package repositories, though active development has slowed considerably in recent years.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not applicable, a volunteer-maintained open-source project rather than a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable, an open-source project originally developed in Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chemtool Review: Free Open-Source Chemical Structure Editor for Linux$q$, seo_title),
  seo_meta_description = COALESCE($q$Chemtool is a free, open-source GTK+ tool for drawing 2D chemical structures on Linux. See features, export formats, and how it compares to modern alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chemtool is a small, free, open-source program for drawing two-dimensional chemical structures on Linux and other X11-based Unix-like operating systems. It was originally written by Thomas Volk, at the time a chemistry and biology student at the University of Ulm in Germany, and was later documented in the German periodical LinuxMagazin. Development subsequently continued under other maintainers, with the project's long-standing home page hosted at the University of Freiburg. Chemtool has been packaged in most major Linux distributions for many years, including through standard repositories like apt and dnf, which is how most current users encounter it rather than building it from source. Note that the exact year of Chemtool's first release could not be independently verified from current sources, so this profile avoids stating a specific founding year rather than guessing one. Functionally, Chemtool provides a focused, no-frills canvas for sketching organic molecules. It supports square and hexagonal backdrop grids to keep bond angles consistent, multiple zoom levels, seven colors, two text fonts plus chemical symbols, and essentially unlimited undo and redo. Its bond-drawing toolkit is unusually thorough for such a lightweight program, covering wedge-shaped bonds, dashed wedge bonds, double and centered double bonds, triple and quadruple bonds, wavy lines, half arrows, and wide bonds, enough to represent most standard organic chemistry notation. Structures can be exported to X bitmap, PNG, PicTeX, XFig, SVG, SXD, MDL molfile, or EPS formats, which makes it easy to drop a diagram into a LaTeX document, a presentation, or a publication. Chemtool can also import files in the Protein Data Bank (PDB) format and the MDL molfile format used by many other cheminformatics tools, which gives it some interoperability with larger chemistry software ecosystems despite its small footprint. A companion command-line helper, cht, calculates the sum formula and exact molecular weight of a Chemtool drawing or a marked fragment of one, a convenience also accessible from within the main application. Because Chemtool is released under the GNU General Public License, it costs nothing to use, modify, or redistribute, and there is no signup, account, or subscription involved. That said, prospective users should understand Chemtool's real limitations before choosing it over more modern tools. It is Linux and X11 only, with no native Windows, macOS, or web-based version, so it is not a fit for users on other platforms without running Linux in a virtual machine or via WSL. Its interface, while functional, looks dated next to actively developed commercial tools like ChemDraw or free web-based editors like Ketcher and MarvinSketch, and it has no cloud sync, collaboration features, version history, or 3D visualization. For a Linux user, student, or educator who just needs to quickly sketch a molecule and export it as a clean vector image, Chemtool remains a lightweight, dependable, and completely free option, best understood today as a stable legacy utility rather than an actively evolving product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '25d9c800-4614-4cac-874b-c91169b5deca';

