-- ── CherryTree ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CherryTree is a free, open-source hierarchical note-taking application created by developer Giuseppe Penone that organizes notes as a tree of nodes, each of which can hold rich text, syntax-highlighted code, images, tables, and embedded files. Released under the GPLv3 license and available for Windows, macOS, and Linux, it stores entire notebooks in a single portable XML or SQLite file, optionally with document-level password protection, which has made it a long-running favorite for offline personal knowledge bases, technical documentation, and IT run-books.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Not applicable, an open-source project maintained by an individual developer and community contributors$q$, company_size),
  headquarters = COALESCE($q$Not applicable, an open-source project$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CherryTree Review: Free Hierarchical Note-Taking App for Windows, Mac, and Linux$q$, seo_title),
  seo_meta_description = COALESCE($q$CherryTree is a free, open-source note-taking app with a tree-based node structure, rich text, syntax highlighting, and password protection.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CherryTree is a free, open-source, hierarchical note-taking application created by developer Giuseppe Penone, first released around 2009, with the codebase later reworked in C++ and GTK by Penone along with contributor Evgenii Gurianov. Rather than organizing notes as a flat list of documents, CherryTree structures every notebook as a tree: each entry is a node that can have any number of child nodes, letting users nest related notes the way folders nest inside other folders. This structure makes CherryTree particularly well suited to information that naturally has sub-topics, such as project documentation, server configuration notes, or a personal knowledge base organized by subject area. Within each node, CherryTree supports genuinely rich formatting rather than plain text alone: bold, italic, underline, strikethrough, text and background colors, hyperlinks, bulleted and numbered lists, tables, embedded images, and file attachments. For technical users, one of CherryTree's standout features is syntax-highlighted code boxes covering dozens of programming and markup languages, which makes it a popular choice for developers and system administrators who want to keep command references, configuration snippets, and troubleshooting notes alongside their prose documentation. It also supports LaTeX syntax for rendering mathematical notation, useful for students and researchers. A defining architectural choice is how CherryTree stores data: an entire notebook, however large, is saved as a single XML or SQLite file by default (a multi-file, directory-based storage option is also available). This makes notebooks trivially easy to back up, move between machines, or carry on a USB drive, and it avoids any dependency on a particular cloud service. Security-conscious users can apply a password to a notebook, which encrypts the entire document; note that this protection applies at the whole-document level rather than to individual nodes. CherryTree is cross-platform, running natively on Windows, macOS, and Linux, and its search functionality can scan an entire note tree or be scoped to a specific branch, which matters once a notebook grows into the hundreds of nodes. What CherryTree does not offer is worth being equally clear about: there is no official mobile app, and it has no built-in real-time cloud sync or multi-user collaboration, so teams or users wanting automatic cross-device sync typically place the storage file inside a service like Dropbox or Nextcloud and rely on that service's own syncing. The interface, while functional and consistent, also looks more utilitarian than newer note-taking apps like Notion or Obsidian, and the tree-based mental model takes some adjustment for users used to flat document lists or a graph-based linking approach. CherryTree remains actively maintained on GitHub by Penone and community contributors, and it is entirely free to use, with the project accepting optional donations rather than charging for the software itself. For anyone who wants a fast, offline-first, deeply nested note-taking tool without any subscription or cloud lock-in, CherryTree continues to be one of the most capable free options available.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd57763a2-33b1-4688-9b26-dbe5e77635fc';

