-- ── Chili Piper ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chili Piper is a B2B revenue-acceleration platform that closes the gap between an inbound lead filling out a form and getting a qualified meeting on a sales rep's calendar. Founded in 2016 by husband-and-wife team Alina and Nicolas Vandenberghe and headquartered in New York City, it combines instant meeting booking, rules-based lead routing, and internal handoff scheduling to help revenue teams cut speed-to-lead and lift inbound conversion rates, with customers reported to include Intuit, Twilio, Forrester, Spotify, and Gong.$q$, short_description),
  pricing_model = COALESCE($q$Custom, quote-based enterprise subscription$q$, pricing_model),
  starting_price = COALESCE($q$Commonly reported starting around $15,000/year, based on custom quotes$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Mid-size private company (exact headcount not fully disclosed publicly; reported to serve roughly 2,000 customers)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chili Piper Review: Meeting Scheduling and Lead Routing Software for Sales Teams$q$, seo_title),
  seo_meta_description = COALESCE($q$Chili Piper automates inbound lead routing and meeting scheduling for B2B sales teams. See features, pricing, pros and cons, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chili Piper is a revenue-acceleration platform built to solve two of the most common leak points in a B2B inbound sales funnel: the delay between a lead submitting a form and a rep following up (speed-to-lead), and the friction of manually finding a mutual meeting time afterward. The company was founded in 2016 by Alina and Nicolas Vandenberghe and is headquartered in New York City. It raised an early Series A of 18 million dollars led by Base10 Partners, with participation from Google's AI-focused venture fund Gradient Ventures and Flashpoint Venture Capital, and has reportedly raised around 58 million dollars in total funding across multiple rounds. Chili Piper's product suite is organized around the moments where inbound leads are won or lost. Concierge, its instant-booking product, embeds a live calendar directly on a website's thank-you page after a form submission, so a prospect can book time with the correct rep immediately instead of waiting for a follow-up email. Distro is Chili Piper's lead-routing engine, assigning inbound leads to the right rep automatically based on rules like territory, existing account ownership, company size, or round-robin distribution, replacing the manual assignment rules many teams previously built and maintained in Salesforce. Handoff extends that same routing and scheduling logic to internal handoffs, automating the process of passing a prospect from an SDR to an account executive, or from sales to onboarding and customer success, without back-and-forth emails. Underpinning all three products is deep integration with Salesforce and HubSpot, letting Chili Piper read and write lead, contact, and opportunity records in near real time, along with calendar integrations for Google Calendar and Outlook. The company acquired scheduling startup KosmoTime in 2022 and underwent a brand refresh in 2024. Chili Piper reports serving roughly 2,000 customers, with publicly cited logos including Intuit, Twilio, Forrester, Spotify, and Gong, positioning it firmly as a tool for established B2B sales and revenue operations organizations rather than early-stage startups. Pricing is not published in detail on Chili Piper's website; the company instead sells through custom quotes, and third-party pricing trackers commonly report plans starting around 15,000 dollars per year, scaling with the number of seats and which products (Concierge, Distro, Handoff) a team adopts. That pricing model, combined with the complexity of configuring routing rules across territories, ownership models, and round-robin logic, generally means Chili Piper is adopted by revenue operations teams at mid-market and enterprise companies with the resources to configure and maintain it, rather than by small businesses evaluating their first scheduling tool. For teams that have outgrown basic calendar-link scheduling and are losing pipeline to slow lead response times or messy manual routing rules, Chili Piper remains one of the more established, purpose-built platforms addressing that specific problem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5c2b1120-f1c7-444d-87ab-c96a49991abc';

