-- ── Churnkey ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Churnkey is a subscription retention platform that helps SaaS companies reduce voluntary and involuntary churn through no-code cancel flows, dunning and payment recovery, A/B testing, and AI-generated retention offers. Founded in 2020 and headquartered near Charleston in Mount Pleasant, South Carolina, and backed by investors including TinySeed and CreativeCo Capital, Churnkey plugs into billing providers like Stripe and Chargebee to intercept the cancellation moment with targeted pause, downgrade, or discount offers, reporting churn reductions of up to 54 percent and payment recovery rates as high as 89 percent for customers.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription, priced by monthly churn volume$q$, pricing_model),
  starting_price = COALESCE($q$$250/month, billed yearly (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small (reported around 15 employees, serving roughly 300 customers)$q$, company_size),
  headquarters = COALESCE($q$Mount Pleasant, South Carolina, United States (Charleston area)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Churnkey Review: Cancel Flow and Churn Reduction Software for SaaS$q$, seo_title),
  seo_meta_description = COALESCE($q$Churnkey builds no-code cancel flows and payment recovery tools to reduce SaaS churn. See pricing, features, pros and cons, and how it works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Churnkey is a subscription retention platform built specifically around the moment a customer tries to cancel, treating that single interaction as a distinct product surface worth designing, testing, and optimizing rather than leaving it to a generic settings page. The company was founded in 2020, is headquartered in Mount Pleasant, South Carolina, near Charleston, and has been backed by investors including startup accelerator TinySeed and CreativeCo Capital, with reported funding of roughly 1.8 million dollars including a 1.5 million dollar growth equity round in April 2024. Churnkey addresses both major categories of subscription churn. Voluntary churn, when a customer actively decides to cancel, is handled through a no-code cancel flow builder that lets non-engineering teams design branching flows with feedback questions, and then present adaptive, AI-personalized offers, such as a plan pause, a downgrade, or a targeted discount, aimed at retaining the customer before they leave entirely. The company reports these cancel flows can reduce active churn by up to 54 percent. Involuntary churn, caused by failed or declined payments, is addressed through Churnkey's dunning and payment recovery tools, which use rules-based retry logic to automatically re-attempt failed charges; the company reports recovering up to 89 percent of failed payments through this system. Layered on top of these core flows are several AI-driven features: an Insights AI module automatically analyzes and categorizes raw cancellation feedback so teams can spot patterns without manually reading every response, a Build with AI feature can generate entire cancel flow steps, copy, and offers from a simple prompt, and automatic AI-powered translation converts cancel flows into multiple languages so international customers get a native-language experience. For mobile-first subscription businesses, Churnkey offers a Hosted Cancel Flow link that can be shared for any platform without engineering work, plus an open-source SDK that can be used as a drop-in component, a headless hook, or a core state machine for teams that want to build a fully custom interface. Churnkey integrates natively with the two most common subscription billing platforms, Stripe and Chargebee, along with Slack and generic webhook-based tooling for alerting and reporting. On the compliance side, all plans include GDPR compliance and SOC 2 certification, which reduces procurement friction for security-conscious buyers. Pricing is tiered primarily by monthly churn volume rather than by seats: the Starter plan costs 250 dollars per month, billed yearly, and is intended for companies with less than 5,000 dollars in monthly churn volume; the Core and Intelligence tiers are reserved for companies with 10,000 dollars or more in monthly churn volume and are sold via custom quote, with Intelligence adding the more advanced AI features like adaptive offers and an account agent; an Enterprise tier adds custom integrations, a dedicated technical account manager, white-label options, and legal support. Churnkey remains a relatively small company, reportedly around 15 employees serving roughly 300 customers, which is worth weighing against its strong reported retention outcomes when evaluating it for a larger or more security-sensitive organization.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '20bf9a2d-068d-44a2-b56c-ac1804fb0eb6';

