INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Native Stripe and Chargebee Integration$q$, $q$Connects directly to the most common subscription billing platforms, plus Slack and webhook alerting.$q$, 7);
