INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Open-source SDK and hosted link options make it usable even for mobile-only subscription apps without deep engineering integration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Built-in GDPR compliance and SOC 2 certification reduce procurement friction for security-conscious buyers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$The entry-level Starter plan is capped for companies under 5,000 dollars per month in churn volume, and higher tiers require a custom quote rather than transparent published pricing$q$, 0);
