INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$The deepest AI and adaptive-offer features are reserved for the higher Intelligence and Enterprise tiers$q$, 2);
