INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$AI-generated retention offers and copy still need human review for brand voice and margin fit$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$What does Churnkey do?$q$, $q$Churnkey builds no-code cancel flows and payment recovery tools that reduce voluntary and involuntary subscription churn.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$How much does Churnkey cost?$q$, $q$Plans start at 250 dollars per month billed yearly for companies under 5,000 dollars per month in churn volume; higher tiers are custom-quoted based on churn volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$What billing platforms does Churnkey integrate with?$q$, $q$Stripe and Chargebee are the primary supported billing providers, alongside Slack and webhook-based integrations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$How much can Churnkey reduce churn by?$q$, $q$The company reports its cancel flows can reduce active churn by up to 54 percent.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Does Churnkey help with failed payments?$q$, $q$Yes, its dunning and payment recovery tools report recovering up to 89 percent of failed payments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Can Churnkey be used in a mobile app?$q$, $q$Yes, via a hosted cancel flow link or an open-source SDK that requires little to no engineering integration.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Is Churnkey compliant with data regulations?$q$, $q$Yes, all plans include GDPR compliance and SOC 2 certification.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$When was Churnkey founded?$q$, $q$Churnkey was founded in 2020.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Intercepting Cancellations With a Personalized Offer$q$, $q$A SaaS company presents a pause, downgrade, or discount offer at the exact moment a customer tries to cancel, before losing them entirely.$q$, $q$SaaS growth and retention teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Recovering Failed-Payment Churn$q$, $q$A subscription business automates dunning and retry logic to recover revenue lost to declined or failed transactions.$q$, $q$Billing, finance, and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$Adding a Compliant Cancel Flow to a Mobile App$q$, $q$A mobile subscription app adds an on-brand, compliant cancellation experience without a dedicated engineering project.$q$, $q$Mobile app product teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$churnkey-problem$q$, $q$The Problem Churnkey Solves$q$, 2, ARRAY[$q$Most SaaS companies lose revenue two ways: customers who actively decide to cancel (voluntary churn), and customers whose payment simply fails and never gets fixed (involuntary churn). Generic, unoptimized cancellation pages tend to make the first problem worse, offering no reason for a wavering customer to stay, while default billing-provider retry logic often leaves the second problem only partially addressed.$q$, $q$Churnkey treats the cancellation moment itself as a product to be designed and iterated on, similar to how a growth team might treat a signup flow. Rather than a single static cancel button, Churnkey's flows collect feedback, present alternatives like a pause or downgrade, and route the customer toward the outcome most likely to retain them, while its payment recovery tools separately work to reduce the churn caused by declined transactions that were never really a cancellation decision at all.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$churnkey-product$q$, $q$Inside Churnkey's Product: Cancel Flows, Recovery, and AI$q$, 2, ARRAY[$q$Churnkey's no-code cancel flow builder lets non-engineering teams design branching flows with feedback questions and offers such as pauses, downgrades, or discounts, and A/B test different versions against each other to see what actually retains customers. Its payment recovery system layers rules-based retry logic on top of a company's existing Stripe or Chargebee billing setup to automatically re-attempt failed charges before they turn into involuntary cancellations.$q$, $q$More recent additions lean on AI: Insights AI automatically analyzes and categorizes raw cancellation feedback into patterns a team can act on, a Build with AI feature can generate flow steps, copy, and offers from a simple prompt, and automatic AI translation localizes cancel flows into multiple languages. For subscription apps distributed through app stores, a Hosted Cancel Flow link or an open-source SDK lets teams add a compliant, on-brand cancellation experience with little or no engineering work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20bf9a2d-068d-44a2-b56c-ac1804fb0eb6', $q$churnkey-pricing$q$, $q$Pricing and Who Churnkey Is Built For$q$, 2, ARRAY[$q$Churnkey's pricing scales with a company's monthly churn volume rather than simple seat counts. The Starter plan, at 250 dollars per month billed yearly, targets companies with under 5,000 dollars in monthly churn volume and includes cancel flows, payment recovery, and core metrics. Companies with 10,000 dollars or more in monthly churn volume move to the custom-quoted Core or Intelligence tiers, with Intelligence adding adaptive AI offers, an account agent, Feedback AI, and AI-powered translations; an Enterprise tier adds custom integrations, a dedicated technical account manager, and white-label options.$q$, $q$This structure, plus built-in GDPR and SOC 2 compliance, makes Churnkey best suited to SaaS and subscription companies with meaningful, measurable churn volume who want a dedicated tool for the cancellation and payment-recovery moment rather than a general customer-engagement platform repurposed for retention.$q$]::text[], 2);
